from .detectors import _draw_settingfrom .molecules import _draw_moleculefrom .sky import _draw_skyfrom .utils import *from criresviz.models import CRIRESSetting, Moleculedef _as_list(obj):    if obj is None:        return []    if isinstance(obj, (list, tuple)):        return obj    return [obj]def _classify(objects):    settings = []    molecules = []    for obj in _as_list(objects):        if isinstance(obj, CRIRESSetting):            settings.append(obj)        elif isinstance(obj, Molecule):            molecules.append(obj)        else:            raise TypeError(                f"Unsupported object type: {type(obj).__name__}"            )    return settings, moleculesdef plot(    *objects,    sky=None,    planet=None,    sky_mode="transmission",    layout="wavelength",    ax=None,):    settings, molecules = _classify(objects)    settings = _as_list(settings)    molecules = _as_list(molecules)        settings = sorted(        settings,        key=lambda s: s.wavelength_range[0]    )        legend = {}        if layout == "compact":        fig, axes = make_compact_axes(settings)            for ax, setting in zip(axes, settings):            _draw_setting(setting, ax)                        if sky is not None:                _draw_sky(sky, ax, sky_mode=sky_mode)            spacing = 0.05            for i, molecule in enumerate(molecules):                y = 1.02 + i * spacing                _draw_molecule(molecule, ax, clip=True, y=y)            update_ylim(ax, len(molecules), spacing)            # legend                            handles, labels = ax.get_legend_handles_labels()                    for h, l in zip(handles, labels):                legend[l] = h                         style_compact_axes(axes, settings)        add_break_marks(axes)                # labels        if sky is not None:            if(sky_mode == "transmission"): fig.supylabel("Transmission")            elif(sky_mode=='radiance'): fig.supylabel("Thermal sky emission")        fig.supxlabel("Wavelength (μm)")                        fig.legend(            legend.values(),            legend.keys(),            loc="upper center",            ncol=len(legend),            frameon=False,        )                return axes        else:        fig, ax = prepare_axes(ax)        for setting in settings:            _draw_setting(setting, ax)            spacing = 0.05        for i, molecule in enumerate(molecules):            y = 1.02 + i * spacing            _draw_molecule(molecule, ax, clip=False, y=y)                    if sky is not None:            _draw_sky(sky, ax, sky_mode=sky_mode)            if(sky_mode=='transmission'): fig.supylabel("Transmission")            elif(sky_mode=='radiance'): fig.supylabel("Thermal sky emission [pht/s/$m^2$/$\mu$m/arcsec$^2$]")        style_axes(ax)        update_ylim(ax, len(molecules), spacing)                #legend        handles, labels = ax.get_legend_handles_labels()                fig.supxlabel("Wavelength (μm)")        fig.legend(            handles,            labels,            frameon=False,        )           return ax